{"meta": null, "content": [{"type": "text", "text": "{"content":"1: \u003c!doctype html\u003e\n2: \u003cmeta charset=\"utf-8\"\u003e\n3: \u003ctitle\u003eCSSContainerRule\u003c/title\u003e\n4: \u003clink rel=\"author\" title=\"Emilio Cobos Álvarez\" href=\"mailto:emilio@crisal.io\"\u003e\n5: \u003clink rel=\"author\" title=\"Mozilla\" href=\"https://mozilla.org\"\u003e\n6: \u003clink rel=\"help\" href=\"https://drafts.csswg.org/css-conditional-5/#the-csscontainerrule-interface\"\u003e\n7: \u003cscript src=/resources/testharness.js\u003e\u003c/script\u003e\n8: \u003cscript src=/resources/testharnessreport.js\u003e\u003c/script\u003e\n9: \u003cstyle id=\"sheet\"\u003e\u003c/style\u003e\n10: \u003cscript\u003e\n11:   const kTests = [\n12:     {\n13:       rule: \"@container name (min-width: 100px) {}\",\n14:       name: \"name\",\n15:       query: \"(min-width: 100px)\",\n16:     },\n17:     {\n18:       rule: \"@container (min-width: 100px) {}\",\n19:       name: \"\",\n20:       query: \"(min-width: 100px)\",\n21:     },\n22:   ];\n23: \n24:   const sheet = document.getElementById(\"sheet\").sheet;\n25:   for (let { rule, name, query } of kTests) {\n26:     test(function() {\n27:       sheet.insertRule(rule, 0);\n28:       let r = sheet.cssRules[0];\n29:       assert_true(r instanceof CSSContainerRule);\n30:       assert_equals(r.containerName, name, \"containerName\");\n31:       assert_equals(r.containerQuery, query, \"containerQuery\");\n32:       assert_equals(r.conditionText, name ? `${name} ${query}` : query, \"conditionText\");\n33:     }, rule)\n34:   }\n35: \u003c/script\u003e\n36: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/servo--be6a2f99@dab40a01527870225a72e50a68411f7077f5cb2c/-/blob/tests/wpt/tests/css/cssom/CSSContainerRule.tentative.html"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: <!doctype html>
