{"meta": null, "content": [{"type": "text", "text": "{"content":"1: \u003c!DOCTYPE html\u003e\n2: \u003ctitle\u003eCSS Conditional Test: CSSContainerRule API\u003c/title\u003e\n3: \u003clink rel=\"help\" href=\"https://drafts.csswg.org/css-conditional-5/#the-csscontainerrule-interface\"\u003e\n4: \u003cscript src=\"/resources/testharness.js\"\u003e\u003c/script\u003e\n5: \u003cscript src=\"/resources/testharnessreport.js\"\u003e\u003c/script\u003e\n6: \u003cstyle id=\"style_elm\"\u003e\n7: \u003c/style\u003e\n8: \u003cscript\u003e\n9:   const sheet = style_elm.sheet;\n10: \n11:   function insertRule(source_text) {\n12:     try {\n13:       while (sheet.cssRules.length) {\n14:         sheet.deleteRule(0);\n15:       }\n16:       sheet.insertRule(source_text);\n17:       return sheet.cssRules[0];\n18:     } catch (e) {\n19:       return null;\n20:     }\n21:   }\n22: \n23:   test(() =\u003e {\n24:     const rule = insertRule(\"@container Name {}\");\n25:     assert_true(!!rule, \"Rule successfully parsed\");\n26:     assert_equals(rule.containerName, \"Name\");\n27:     assert_equals(rule.containerQuery, \"\");\n28:   }, \"containerName without query\");\n29: \n30:   test(() =\u003e {\n31:     const rule = insertRule(\"@container (width \u003e 300px) {}\");\n32:     assert_true(!!rule, \"Rule successfully parsed\");\n33:     assert_equals(rule.containerName, \"\");\n34:     assert_equals(rule.containerQuery, \"(width \u003e 300px)\");\n35:   }, \"containerQuery without name\");\n36: \n37:   test(() =\u003e {\n38:     const rule = insertRule(\"@container Name (width \u003e 300px) {}\");\n39:     assert_true(!!rule, \"Rule successfully parsed\");\n40:     assert_equals(rule.containerName, \"Name\");\n41:     assert_equals(rule.containerQuery, \"(width \u003e 300px)\");\n42:   }, \"containerName and containerQuery\");\n43: \u003c/script\u003e\n44: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/servo--be6a2f99@dab40a01527870225a72e50a68411f7077f5cb2c/-/b