68:         &self,
69:         rules: &Arc<Locked<CssRules>>,
70:         guard: &SharedRwLockReadGuard,
71:     ) {
72:         if let Some(rulelist) = self.rulelist.get() {
73:             rulelist.update_rules(RulesSource::Rules(rules.clone()), guard);
74:         }
75:     }
76: }
